// ─── STUDENT TASKS / ASSIGNMENTS ──────────────────────────────────────────────
const StudentTasks = () => {
  const [assignments, setAssignments] = useState([]);
  const [loading, setLoading]         = useState(true);
  const [selected, setSelected]       = useState(null);
  const [answer, setAnswer]           = useState("");
  const [submitting, setSubmitting]   = useState(false);
  const [filterStatus, setFilterStatus] = useState("ALL");

  useEffect(() => {
    getStudentAssignments()
      .then(d => {
        console.log("📋 Assignments API Response:", d);
        const data = Array.isArray(d) ? d : (d?.data ? d.data : []);
        console.log("📋 Processed Assignments:", data);
        setAssignments(data);
      })
      .catch(err => {
        console.error("❌ Assignment fetch error:", err);
        setAssignments([]);
      })
      .finally(() => setLoading(false));
  }, []);

  const handleSubmit = async () => {
    if (!answer.trim()) { alert("Please write your answer."); return; }
    try {
      setSubmitting(true);
      await submitAssignment(selected.id, { answer });
      setAssignments(a => a.map(x => x.id === selected.id ? { ...x, submitted: true } : x));
      setSelected(null); setAnswer("");
      alert("✅ Assignment submitted!");
    } catch (e) { alert("Error: " + e.message); }
    finally { setSubmitting(false); }
  };

  const statusColor = { PENDING: T.accentY, SUBMITTED: T.accentG, GRADED: T.accent, OVERDUE: "#ef4444" };
  const statusIcon = { PENDING: "⏳", SUBMITTED: "✅", GRADED: "📊", OVERDUE: "🔴" };

  // Calculate statistics
  const stats = {
    total: assignments.length,
    pending: assignments.filter(a => !a.submitted && a.status !== "GRADED").length,
    submitted: assignments.filter(a => a.submitted && !a.grade && a.status !== "GRADED").length,
    graded: assignments.filter(a => a.grade != null && a.grade !== undefined && a.grade !== "").length,
    overdue: assignments.filter(a => a.status === "OVERDUE" || new Date(a.dueDate) < new Date()).length,
  };

  // Calculate average grade - handle various field names
  const graded = assignments.filter(a => (a.grade != null && a.grade !== undefined && a.grade !== ""));
  const avgGrade = graded.length > 0 ? Math.round(graded.reduce((s, a) => s + (Number(a.grade) || 0), 0) / graded.length) : 0;

  // Overall completion percentage
  const completionPercentage = stats.total > 0 ? Math.round(((stats.submitted + stats.graded) / stats.total) * 100) : 0;

  // Filter assignments
  let filteredAssignments = assignments;
  if (filterStatus === "PENDING") filteredAssignments = assignments.filter(a => !a.submitted && a.status !== "GRADED");
  else if (filterStatus === "SUBMITTED") filteredAssignments = assignments.filter(a => a.submitted && !a.grade);
  else if (filterStatus === "GRADED") filteredAssignments = assignments.filter(a => a.grade != null);
  else if (filterStatus === "OVERDUE") filteredAssignments = assignments.filter(a => a.status === "OVERDUE" || new Date(a.dueDate) < new Date());

  // Grade distribution data
  const gradeRanges = { "A (90-100)": 0, "B (80-89)": 0, "C (70-79)": 0, "D (60-69)": 0, "F (<60)": 0 };
  graded.forEach(a => {
    const g = Number(a.grade) || 0;
    if (g >= 90) gradeRanges["A (90-100)"]++;
    else if (g >= 80) gradeRanges["B (80-89)"]++;
    else if (g >= 70) gradeRanges["C (70-79)"]++;
    else if (g >= 60) gradeRanges["D (60-69)"]++;
    else gradeRanges["F (<60)"]++;
  });

  const gradeChartData = Object.entries(gradeRanges).filter(([, v]) => v > 0).map(([name, value]) => ({ name, value }));
  const statusChartData = [
    { name: "Pending", value: stats.pending, fill: statusColor.PENDING },
    { name: "Submitted", value: stats.submitted, fill: statusColor.SUBMITTED },
    { name: "Graded", value: stats.graded, fill: statusColor.GRADED },
    { name: "Overdue", value: stats.overdue, fill: statusColor.OVERDUE },
  ].filter(d => d.value > 0);

  return (
    <div className="fade-up">
      <PageHeader title="📋 Tasks & Assignments" subtitle={`${assignments.length} assignment${assignments.length !== 1 ? "s" : ""}`} />

      {loading ? <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
      : assignments.length === 0 ? (
        <Card><div style={{ padding: 40, textAlign: "center", color: T.muted }}>
          <div style={{ fontSize: 40, marginBottom: 10 }}>📝</div>
          <div style={{ fontFamily: "Syne", fontWeight: 700 }}>No assignments yet</div>
          <div style={{ fontSize: 12, color: T.muted, marginTop: 10 }}>Check the console to debug the API response</div>
        </div></Card>
      ) : (
        <>
          {/* Statistics Cards */}
          <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit, minmax(200px, 1fr))", gap: 16, marginBottom: 24 }}>
            {[
              { label: "Total", value: stats.total, color: T.primary, icon: "📚" },
              { label: "Pending", value: stats.pending, color: T.accentY, icon: "⏳" },
              { label: "Submitted", value: stats.submitted, color: T.accentG, icon: "✅" },
              { label: "Graded", value: stats.graded, color: T.accent, icon: "📊" },
              { label: "Avg Grade", value: `${avgGrade}%`, color: T.primary, icon: "🎯" },
            ].map((s, i) => (
              <Card key={i} style={{ padding: 18, textAlign: "center" }}>
                <div style={{ fontSize: 28, marginBottom: 8 }}>{s.icon}</div>
                <div style={{ fontSize: 11, color: T.muted, marginBottom: 6 }}>{s.label}</div>
                <div style={{ fontSize: 22, fontWeight: 800, color: s.color }}>{s.value}</div>
              </Card>
            ))}
          </div>

          {/* Overall Completion */}
          <Card style={{ padding: 20, marginBottom: 24 }}>
            <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 12 }}>
              <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15 }}>📈 Overall Completion</div>
              <div style={{ fontSize: 18, fontWeight: 800, color: T.primary }}>{completionPercentage}%</div>
            </div>
            <div style={{ height: 12, background: T.bg3, borderRadius: 50, overflow: "hidden" }}>
              <div style={{
                height: "100%",
                width: `${completionPercentage}%`,
                background: `linear-gradient(90deg, ${T.primary}, ${T.accent})`,
                transition: "width 0.4s"
              }} />
            </div>
          </Card>

          {/* Charts */}
          {statusChartData.length > 0 || gradeChartData.length > 0 ? (
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 20, marginBottom: 24 }}>
              {statusChartData.length > 0 && (
                <Card style={{ padding: 20 }}>
                  <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15, marginBottom: 16 }}>Assignment Status</div>
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 16, justifyContent: "center" }}>
                    {statusChartData.map((item, i) => (
                      <div key={i} style={{ textAlign: "center" }}>
                        <div style={{
                          width: 80, height: 80, borderRadius: "50%",
                          background: item.fill + "30", border: `3px solid ${item.fill}`,
                          display: "flex", alignItems: "center", justifyContent: "center",
                          fontSize: 20, fontWeight: 800, color: item.fill, marginBottom: 8
                        }}>
                          {item.value}
                        </div>
                        <div style={{ fontSize: 12, fontWeight: 600 }}>{item.name}</div>
                      </div>
                    ))}
                  </div>
                </Card>
              )}

              {gradeChartData.length > 0 && (
                <Card style={{ padding: 20 }}>
                  <div style={{ fontFamily: "Syne", fontWeight: 700, fontSize: 15, marginBottom: 16 }}>Grade Distribution</div>
                  <ResponsiveContainer width="100%" height={200}>
                    <BarChart data={gradeChartData}>
                      <XAxis dataKey="name" tick={{ fontSize: 11 }} />
                      <YAxis tick={{ fontSize: 11 }} />
                      <Bar dataKey="value" fill={T.primary} radius={[8, 8, 0, 0]} />
                    </BarChart>
                  </ResponsiveContainer>
                </Card>
              )}
            </div>
          ) : null}

          {/* Filter Buttons */}
          <div style={{ display: "flex", gap: 8, marginBottom: 20, flexWrap: "wrap" }}>
            {["ALL", "PENDING", "SUBMITTED", "GRADED", "OVERDUE"].map(status => (
              <button
                key={status}
                onClick={() => setFilterStatus(status)}
                style={{
                  padding: "8px 16px",
                  borderRadius: 50,
                  cursor: "pointer",
                  fontSize: 12,
                  fontWeight: 600,
                  border: `1.5px solid ${filterStatus === status ? T.primary : T.border}`,
                  background: filterStatus === status ? `${T.primary}20` : "transparent",
                  color: filterStatus === status ? T.primary : T.muted,
                  transition: "all 0.2s"
                }}
              >
                {statusIcon[status] || "📋"} {status}
              </button>
            ))}
          </div>

          {/* Assignments List */}
          <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
            {filteredAssignments.length === 0 ? (
              <Card><div style={{ padding: 40, textAlign: "center", color: T.muted }}>
                <div style={{ fontSize: 30, marginBottom: 10 }}>✨</div>
                <div style={{ fontFamily: "Syne", fontWeight: 700 }}>No {filterStatus.toLowerCase()} assignments</div>
              </div></Card>
            ) : (
              filteredAssignments.map(a => (
                <Card key={a.id} style={{ padding: 18 }}>
                  <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 12 }}>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontWeight: 700, fontSize: 15, marginBottom: 4 }}>{a.title}</div>
                      <div style={{ fontSize: 12, color: T.muted, marginBottom: 6 }}>{a.description}</div>
                      <div style={{ fontSize: 11, color: T.muted }}>
                        📅 Due: {a.dueDate || "—"} · 📚 {a.courseTitle || "General"}
                      </div>
                    </div>
                    <div style={{ display: "flex", flexDirection: "column", gap: 6, alignItems: "flex-end", flexShrink: 0 }}>
                      <span style={{ fontSize: 11, fontWeight: 700, borderRadius: 50, padding: "3px 10px",
                        background: `${statusColor[a.submitted ? "SUBMITTED" : "PENDING"]}20`,
                        color: statusColor[a.submitted ? "SUBMITTED" : "PENDING"] }}>
                        {statusIcon[a.submitted ? "SUBMITTED" : "PENDING"]} {a.submitted ? "Submitted" : "Pending"}
                      </span>
                      {!a.submitted && (
                        <Btn size="xs" variant="primary" onClick={() => { setSelected(a); setAnswer(""); }}>
                          Submit →
                        </Btn>
                      )}
                    </div>
                  </div>
                  {a.grade != null && (
                    <div style={{ marginTop: 10, background: `${T.accentG}12`, borderRadius: 8, padding: "8px 12px" }}>
                      <span style={{ fontWeight: 700, color: T.accentG }}>📊 Grade: {a.grade}/100</span>
                      {a.feedback && <span style={{ fontSize: 12, color: T.muted, marginLeft: 12 }}>"{a.feedback}"</span>}
                    </div>
                  )}
                </Card>
              ))
            )}
          </div>
        </>
      )}

      {/* Submit Modal */}
      <Modal open={!!selected} onClose={() => setSelected(null)} title={`Submit: ${selected?.title}`}>
        <div style={{ marginBottom: 14 }}>
          <label style={{ fontSize: 11, fontWeight: 700, color: T.muted, textTransform: "uppercase",
            letterSpacing: 1, display: "block", marginBottom: 6 }}>Your Answer</label>
          <textarea rows={6} value={answer} onChange={e => setAnswer(e.target.value)}
            placeholder="Write your answer here..."
            style={{ width: "100%", background: T.bg3, border: `1.5px solid ${T.border}`,
              borderRadius: 9, padding: "10px 14px", fontSize: 13, color: T.text,
              outline: "none", resize: "vertical", fontFamily: "DM Sans", boxSizing: "border-box" }} />
        </div>
        <Btn variant="primary" full onClick={handleSubmit} disabled={submitting}>
          {submitting ? "Submitting…" : "Submit Assignment →"}
        </Btn>
      </Modal>
    </div>
  );
};

