// student performence>>>>>>
export const Performance = () => {
  const [loading, setLoading] = useState(true);
  const [rawAttendance, setRawAttendance] = useState([]);
  const [attendance, setAttendance] = useState([]);
  const [tasks, setTasks] = useState([]);
  const [grades, setGrades] = useState([]);
  const [period, setPeriod] = useState("WEEKLY"); // WEEKLY or MONTHLY

  function getISOWeek(date) {
    const d = new Date(Date.UTC(date.getFullYear(), date.getMonth(), date.getDate()));
    const dayNum = d.getUTCDay() || 7;
    d.setUTCDate(d.getUTCDate() + 4 - dayNum);
    const yearStart = new Date(Date.UTC(d.getUTCFullYear(), 0, 1));
    return Math.ceil((((d - yearStart) / 86400000) + 1) / 7);
  }

  function transformAttendanceByWeek(data) {
    const weeks = {};

    data.forEach(a => {
      const d = new Date(a.date);

      // Get proper ISO week number and month/year
      const weekNum = getISOWeek(d);
      const monthYear = d.toLocaleDateString("en-IN", { month: "short", year: "numeric" });
      const dateRange = d.toLocaleDateString("en-IN", { day: "2-digit", month: "short" });
      const week = `Week ${weekNum} • ${dateRange} (${monthYear})`;

      if (!weeks[week]) {
        weeks[week] = { week, present: 0, absent: 0 };
      }

      if (a.status === "PRESENT") {
        weeks[week].present += 1;
      } else {
        weeks[week].absent += 1;
      }
    });

    return Object.values(weeks);
  }

  function transformAttendanceByMonth(data) {
    const months = {};

    data.forEach(a => {
      const d = new Date(a.date);
      const monthYear = d.toLocaleDateString("en-IN", { month: "long", year: "numeric" });

      if (!months[monthYear]) {
        months[monthYear] = { week: monthYear, present: 0, absent: 0 };
      }

      if (a.status === "PRESENT") {
        months[monthYear].present += 1;
      } else {
        months[monthYear].absent += 1;
      }
    });

    return Object.values(months);
  }

  // Custom Tooltip Component
  const CustomTooltip = ({ active, payload }) => {
    if (active && payload && payload.length) {
      const data = payload[0].payload;
      return (
        <div style={{
          background: T.bg3,
          border: `1.5px solid ${T.border}`,
          borderRadius: 9,
          padding: "12px 14px",
          color: T.text,
          fontSize: 13,
          fontWeight: 600
        }}>
          <div style={{ marginBottom: 6 }}>{data.week}</div>
          <div style={{ color: "#10b981", marginBottom: 4 }}>Present: {data.present}</div>
          <div style={{ color: "#ef4444" }}>Absent: {data.absent}</div>
        </div>
      );
    }
    return null;
  };

  useEffect(() => {
  getStudentAttendanceTrack()
    .then(data => {
      const rawData = data.attendance || [];
      setRawAttendance(rawData);

      const formatted = period === "WEEKLY" 
        ? transformAttendanceByWeek(rawData)
        : transformAttendanceByMonth(rawData);

      setAttendance(formatted);
      setTasks(data.tasks || []);
      setGrades(data.grades || []);
      setLoading(false);
    })
    .catch(err => {
      console.error(err);
      setLoading(false);
    });
}, []);

  // Update chart when period changes
  useEffect(() => {
    if (rawAttendance.length > 0) {
      const formatted = period === "WEEKLY" 
        ? transformAttendanceByWeek(rawAttendance)
        : transformAttendanceByMonth(rawAttendance);
      setAttendance(formatted);
    }
  }, [period]);

  // Calculate total present and absent
  const totalPresent = attendance.reduce((sum, item) => sum + item.present, 0);
  const totalAbsent = attendance.reduce((sum, item) => sum + item.absent, 0);

  if (loading) return <div style={{ padding: 32 }}>Loading performance…</div>;

  return (
    <div className="fade-up">
      <PageHeader title="📊 My Performance" subtitle="Attendance, Tasks, Assignments & Grades" />

      {/* Attendance */}
      <Card style={{ padding: 20, marginBottom: 24 }}>
        <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 16 }}>
          <h3 style={{ margin: 0 }}>Attendance ({period === "WEEKLY" ? "Weekly" : "Monthly"})</h3>
          <select 
            value={period} 
            onChange={(e) => setPeriod(e.target.value)}
            style={{
              padding: "8px 12px",
              borderRadius: 6,
              border: `1.5px solid ${T.border}`,
              background: T.bg3,
              color: T.text,
              fontSize: 13,
              fontWeight: 600,
              cursor: "pointer",
              outline: "none"
            }}
          >
            <option value="WEEKLY">Weekly View</option>
            <option value="MONTHLY">Monthly View</option>
          </select>
        </div>

        {attendance.length === 0 ? (
          <p style={{ color: "#777" }}>No attendance data available.</p>
        ) : (
          <>
            <ResponsiveContainer width="100%" height={500}>
              <BarChart 
                data={attendance} 
                margin={{ top: 20, right: 30, left: 0, bottom: 120 }}
              >
                <XAxis 
                  dataKey="week" 
                  angle={-45} 
                  textAnchor="end" 
                  height={120}
                  interval={0}
                  tick={{ fontSize: 12, fill: T.text }}
                />
                <YAxis tick={{ fontSize: 12, fill: T.text }} />
                <Tooltip content={<CustomTooltip />} cursor={{ fill: `${T.primary}10` }} />
                <Legend />
                <Bar dataKey="present" fill="#10b981" name="Present" />
                <Bar dataKey="absent" fill="#ef4444" name="Absent" />
              </BarChart>
            </ResponsiveContainer>

            {/* Summary Statistics */}
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginTop: 20 }}>
              <div style={{
                background: "#10b98120",
                border: `1.5px solid #10b981`,
                borderRadius: 9,
                padding: "16px",
                textAlign: "center"
              }}>
                <div style={{ fontSize: 12, color: T.muted, marginBottom: 6 }}>Total Present</div>
                <div style={{ fontSize: 28, fontWeight: 800, color: "#10b981" }}>{totalPresent}</div>
              </div>
              <div style={{
                background: "#ef444420",
                border: `1.5px solid #ef4444`,
                borderRadius: 9,
                padding: "16px",
                textAlign: "center"
              }}>
                <div style={{ fontSize: 12, color: T.muted, marginBottom: 6 }}>Total Absent</div>
                <div style={{ fontSize: 28, fontWeight: 800, color: "#ef4444" }}>{totalAbsent}</div>
              </div>
            </div>
          </>
        )}
      </Card>

      {/* Tasks & Assignments */}
      <Card style={{ padding: 20, marginBottom: 24 }}>
        <h3>Tasks & Assignments</h3>
        {tasks.length === 0 ? (
          <p style={{ color: "#777" }}>No tasks or assignments yet.</p>
        ) : (
          <ul>
            {tasks.map(t => (
              <li key={t.id}>
                <strong>{t.title}</strong> — {t.status} — Due: {t.dueDate}
              </li>
            ))}
          </ul>
        )}
      </Card>

      {/* Grades */}
      <Card style={{ padding: 20 }}>
        <h3>Grades</h3>
        {grades.length === 0 ? (
          <p style={{ color: "#777" }}>No grades recorded yet.</p>
        ) : (
          <table style={{ width: "100%", borderCollapse: "collapse" }}>
            <thead>
              <tr>
                <th>Course</th>
                <th>Assignment</th>
                <th>Grade</th>
              </tr>
            </thead>
            <tbody>
              {grades.map(g => (
                <tr key={g.id}>
                  <td>{g.course}</td>
                  <td>{g.assignment}</td>
                  <td>{g.grade}</td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </Card>
    </div>
  );
};

// ─── STUDENT NOTIFICATIONS ────────────────────────────────────────────────────
const StudentNotifications = () => {
  const [notifs, setNotifs]   = useState([]);
  const [loading, setLoading] = useState(true);
  const [filter, setFilter]   = useState("ALL");

  useEffect(() => {
    getStudentNotifications()
      .then(d => setNotifs(Array.isArray(d) ? d : []))
      .catch(console.error)
      .finally(() => setLoading(false));
  }, []);

  const handleMarkRead = async id => {
    await markStudentNotifRead(id).catch(console.error);
    setNotifs(n => n.map(x => x.id === id ? { ...x, read: true } : x));
  };
  const handleMarkAll = async () => {
    await markStudentNotifReadAll().catch(console.error);
    setNotifs(n => n.map(x => ({ ...x, read: true })));
  };

  const typeIcon  = { INFO: "ℹ️", WARNING: "⚠️", SUCCESS: "✅", ERROR: "❌" };
  const typeColor = { INFO: T.accent, WARNING: T.accentY, SUCCESS: T.accentG, ERROR: "#ef4444" };
  const unread    = notifs.filter(n => !n.read).length;
  const filtered  = filter === "ALL" ? notifs
    : filter === "UNREAD" ? notifs.filter(n => !n.read)
    : notifs.filter(n => n.type === filter);

  return (
    <div className="fade-up">
      <PageHeader title="Notifications"
        subtitle={`${unread} unread · ${notifs.length} total`}
        actions={[<Btn variant="ghost" size="sm" onClick={handleMarkAll} disabled={unread === 0}>✓ Mark All Read</Btn>]} />
      <div style={{ display: "flex", gap: 8, marginBottom: 16, flexWrap: "wrap" }}>
        {[
          { key: "ALL",     label: `All (${notifs.length})` },
          { key: "UNREAD",  label: `🔵 Unread (${unread})` },
          { key: "INFO",    label: "ℹ️ Info" },
          { key: "WARNING", label: "⚠️ Alerts" },
          { key: "SUCCESS", label: "✅ Success" },
        ].map(f => (
          <button key={f.key} onClick={() => setFilter(f.key)}
            style={{ padding: "6px 14px", borderRadius: 50, cursor: "pointer",
              border: `1.5px solid ${filter === f.key ? T.primary : T.border}`,
              background: filter === f.key ? `${T.primary}20` : "transparent",
              color: filter === f.key ? T.primary : T.muted, fontWeight: 600, fontSize: 12 }}>
            {f.label}
          </button>
        ))}
      </div>
      <Card>
        {loading ? <div style={{ padding: 32, textAlign: "center", color: T.muted }}>Loading…</div>
        : filtered.length === 0 ? (
          <div style={{ padding: 40, textAlign: "center", color: T.muted }}>
            <div style={{ fontSize: 40, marginBottom: 10 }}>🔔</div>
            <div style={{ fontFamily: "Syne", fontWeight: 700 }}>No notifications</div>
          </div>
        ) : filtered.map((n, i) => (
          <div key={n.id} onClick={() => !n.read && handleMarkRead(n.id)}
            style={{ display: "flex", gap: 14, padding: "14px 0",
              borderBottom: i < filtered.length - 1 ? `1px solid rgba(45,33,96,.3)` : "none",
              alignItems: "flex-start", cursor: !n.read ? "pointer" : "default",
              background: !n.read ? `${T.primary}05` : "transparent" }}>
            <div style={{ width: 40, height: 40, borderRadius: 10, flexShrink: 0,
              background: `${typeColor[n.type] || T.primary}18`,
              display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20 }}>
              {typeIcon[n.type] || "🔔"}
            </div>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div style={{ fontSize: 14, fontWeight: n.read ? 500 : 700 }}>{n.title}</div>
              <div style={{ fontSize: 12, color: T.muted, marginTop: 3, lineHeight: 1.5 }}>{n.message}</div>
              <div style={{ fontSize: 11, color: T.muted, marginTop: 5 }}>
                {n.createdAt ? new Date(n.createdAt).toLocaleString("en-IN", {
                  day: "numeric", month: "short", hour: "2-digit", minute: "2-digit" }) : ""}
              </div>
            </div>
            {!n.read && <div style={{ width: 10, height: 10, borderRadius: "50%",
              background: typeColor[n.type] || T.primaryL, flexShrink: 0, marginTop: 6 }} />}
          </div>
        ))}
      </Card>
    </div>
  );
};

